const items = $input.all();

return items.map(item => {
  const url = item.json.resume_url;

  // Extract the file ID from the Drive URL
  let fileId = '';

  if (url.includes('id=')) {
    fileId = url.split('id=')[1].split('&')[0];
  } else if (url.includes('/d/')) {
    fileId = url.split('/d/')[1].split('/')[0];
  }

  return {
    json: {
      ...item.json,
      file_id: fileId,
      download_url: `https://drive.google.com/uc?export=download&id=${fileId}`
    }
  };
});

const items = $input.all();
return items.map(item => {
  let text = item.json.candidates[0].content.parts[0].text;

  // Remove markdown backticks if Gemini adds them
  text = text.replace(/```json/g, '').replace(/```/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch(e) {
    parsed = {
      score: 0,
      classification: 'average',
      summary: 'Could not parse AI response',
      strengths: 'N/A',
      concerns: 'N/A',
      recommendation: 'Manual review required'
    };
  }

  // Safely convert arrays or objects to plain strings
  const toSafeString = (val) => {
    if (val === null || val === undefined) return '';
    if (Array.isArray(val)) return val.join('; ');
    if (typeof val === 'object') return JSON.stringify(val);
    return String(val).trim();
  };

  return {
    json: {
      name: item.json.name,
      email: item.json.email,
      role: item.json.role,
      resume_url: item.json.resume_url,
      years_experience: item.json.years_experience,
      timestamp: item.json.timestamp,
      score: Number(parsed.score) || 0,
      classification: toSafeString(parsed.classification),
      summary: toSafeString(parsed.summary),
      strengths: toSafeString(parsed.strengths),
      concerns: toSafeString(parsed.concerns),
      recommendation: toSafeString(parsed.recommendation),
      status: 'screened'
    }
  };
});

const items = $input.all();

return items.map(item => {
  const role = item.json.role;
  const name = item.json.name;
  const years = item.json.years_experience;
  const extra = item.json.extra_field;
  const resume = item.json.resume_text;

  const swePrompt = `You are a technical hiring evaluator for a Software Engineer position. Evaluate this candidate strictly on software engineering criteria.

Evaluate based on:
- Programming languages and frameworks
- Years and quality of technical experience
- System design and architecture knowledge
- DevOps, databases, and tooling
- Overall technical depth

Candidate Details:
Name: ${name}
Years of Experience: ${years}
Primary Languages: ${extra}
Resume:
${resume}

Respond ONLY in this exact JSON format with no extra text, no markdown, no backticks:
{
  "score": <number 1-100>,
  "classification": "<strong|average|weak>",
  "summary": "<2-3 sentence summary>",
  "strengths": "<key strengths>",
  "concerns": "<key concerns>",
  "recommendation": "<interview recommendation>"
}`;

  const bdmPrompt = `You are a hiring evaluator for a Business Development Manager position. Evaluate this candidate strictly on business development criteria.

Evaluate based on:
- Sales and revenue generation track record
- B2B relationship and pipeline management
- Negotiation and closing ability
- Strategic thinking and market knowledge
- Leadership and communication skills

Candidate Details:
Name: ${name}
Years of Experience: ${years}
Industries: ${extra}
Resume:
${resume}

Respond ONLY in this exact JSON format with no extra text, no markdown, no backticks:
{
  "score": <number 1-100>,
  "classification": "<strong|average|weak>",
  "summary": "<2-3 sentence summary>",
  "strengths": "<key strengths>",
  "concerns": "<key concerns>",
  "recommendation": "<interview recommendation>"
}`;

  const prompt = role === 'SWE' ? swePrompt : bdmPrompt;

  // Build the entire Gemini request body here
  const geminiBody = {
    contents: [
      {
        parts: [
          {
            text: prompt
          }
        ]
      }
    ],
    generationConfig: {
      temperature: 0.3
    }
  };

  return {
    json: {
      ...item.json,
      ai_prompt: prompt,
      gemini_body: JSON.stringify(geminiBody)
    }
  };
});
